"use client";

import { useEffect, useMemo, useState } from "react";
import { useFormStatus } from "react-dom";

type EditClassModalProps = {
  classId: string;
  initialName: string;
  initialDescription?: string;
  submitAction: (formData: FormData) => void | Promise<void>;
};

export function EditClassModal({
  classId,
  initialName,
  initialDescription,
  submitAction,
}: EditClassModalProps) {
  const [open, setOpen] = useState(false);
  const fieldId = useMemo(() => classId.replace(/[^a-zA-Z0-9_-]/g, "_"), [classId]);

  useEffect(() => {
    if (!open) {
      return;
    }

    const onKeyDown = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setOpen(false);
      }
    };

    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [open]);

  return (
    <>
      <button
        type="button"
        onClick={() => setOpen(true)}
        className="rounded-md border border-zinc-300 px-3 py-1.5 text-xs font-medium text-zinc-800 hover:bg-zinc-100"
      >
        Edit
      </button>

      {open ? (
        <div className="fixed inset-0 z-40 flex items-center justify-center bg-black/50 p-4">
          <div className="w-full max-w-md rounded-xl bg-white p-5 shadow-xl">
            <h3 className="text-lg font-semibold text-zinc-900">Edit Class</h3>
            <p className="mt-1 text-sm text-zinc-700">
              Update class details for <span className="font-mono">{classId}</span>.
            </p>

            <form action={submitAction} className="mt-4 space-y-4">
              <input type="hidden" name="class_id" value={classId} />

              <div className="space-y-2">
                <label
                  htmlFor={`edit-name-${fieldId}`}
                  className="block text-sm font-medium text-zinc-900"
                >
                  Name <span className="text-red-600">*</span>
                </label>
                <input
                  id={`edit-name-${fieldId}`}
                  name="name"
                  type="text"
                  required
                  defaultValue={initialName}
                  className="w-full rounded-lg border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900"
                />
              </div>

              <div className="space-y-2">
                <label
                  htmlFor={`edit-description-${fieldId}`}
                  className="block text-sm font-medium text-zinc-900"
                >
                  Description
                </label>
                <textarea
                  id={`edit-description-${fieldId}`}
                  name="description"
                  rows={3}
                  defaultValue={initialDescription ?? ""}
                  className="w-full rounded-lg border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900"
                />
              </div>

              <div className="flex items-center justify-end gap-2">
                <button
                  type="button"
                  onClick={() => setOpen(false)}
                  className="rounded-lg border border-zinc-300 px-3 py-2 text-sm font-medium text-zinc-900 hover:bg-zinc-100"
                >
                  Cancel
                </button>
                <SubmitButton onComplete={() => setOpen(false)} />
              </div>
            </form>
          </div>
        </div>
      ) : null}
    </>
  );
}

function SubmitButton({ onComplete }: { onComplete: () => void }) {
  const { pending } = useFormStatus();

  useEffect(() => {
    if (!pending) {
      return;
    }
    onComplete();
  }, [pending, onComplete]);

  return (
    <button
      type="submit"
      disabled={pending}
      className="rounded-lg bg-zinc-900 px-3 py-2 text-sm font-medium text-white hover:bg-zinc-700 disabled:cursor-not-allowed disabled:bg-zinc-400"
    >
      {pending ? "Saving..." : "Save"}
    </button>
  );
}

import { makeFunctionReference } from "convex/server";
import Link from "next/link";
import { redirect } from "next/navigation";

import { AddClassModal } from "./add-class-modal";
import { EditClassModal } from "./edit-class-modal";
import { getServerAuthSession } from "@/lib/auth";
import { createConvexHttpClient } from "@/lib/convexHttp";

type ClassRow = {
  class_id: string;
  class_name: string;
  description?: string;
  total_sessions: number;
  status: "active" | "inactive";
};

type AdminClassesPageProps = {
  searchParams: Promise<{ status?: string; error?: string }>;
};

export default async function AdminClassesPage({
  searchParams,
}: AdminClassesPageProps) {
  const session = await getServerAuthSession();
  if (!session?.user?.username) {
    redirect("/admin/login?error=Please%20log%20in%20to%20continue.");
  }

  const params = await searchParams;
  const errorMessage = params.error ?? undefined;
  const classCreated = params.status === "class_created";
  const classUpdated = params.status === "class_updated";
  const isSuperAdmin = session.user.role === "super_admin";
  const adminUsername = session.user.username;

  const classes = await loadClassListPageData();

  async function addClassAction(formData: FormData) {
    "use server";

    const name = (formData.get("name") as string | null)?.trim() ?? "";
    const description =
      (formData.get("description") as string | null)?.trim() || undefined;

    if (!name) {
      redirect(
        `/admin/classes?error=${encodeURIComponent("Class name is required.")}`
      );
    }

    try {
      const client = createConvexHttpClient();
      await client.mutation(
        makeFunctionReference<"mutation">("adminClasses:createClass"),
        { name, description, admin_username: adminUsername }
      );
    } catch {
      redirect(
        `/admin/classes?error=${encodeURIComponent("Failed to create class. Please try again.")}`
      );
    }

    redirect("/admin/classes?status=class_created");
  }

  async function editClassAction(formData: FormData) {
    "use server";

    const classId = (formData.get("class_id") as string | null)?.trim() ?? "";
    const name = (formData.get("name") as string | null)?.trim() ?? "";
    const description =
      (formData.get("description") as string | null)?.trim() ?? "";

    if (!classId || !name) {
      redirect(
        `/admin/classes?error=${encodeURIComponent("Class ID and name are required.")}`
      );
    }

    try {
      const client = createConvexHttpClient();
      await client.mutation(
        makeFunctionReference<"mutation">("adminClasses:updateClass"),
        {
          class_id: classId,
          name,
          description,
          admin_username: adminUsername,
        }
      );
    } catch {
      redirect(
        `/admin/classes?error=${encodeURIComponent("Failed to update class. Please try again.")}`
      );
    }

    redirect("/admin/classes?status=class_updated");
  }

  return (
    <main className="mx-auto min-h-screen w-full max-w-5xl space-y-6 px-4 py-8">
      <section className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-zinc-900">Classes</h1>
          <p className="text-sm text-zinc-700">
            Signed in as{" "}
            <span className="font-medium">{session.user.username}</span> (
            {session.user.role})
          </p>
        </div>

        {isSuperAdmin ? (
          <AddClassModal
            submitAction={addClassAction}
            errorMessage={errorMessage}
            success={classCreated}
          />
        ) : null}
      </section>

      {!isSuperAdmin && errorMessage ? (
        <p className="rounded-lg bg-red-50 p-3 text-sm text-red-700">{errorMessage}</p>
      ) : null}

      {classUpdated ? (
        <p className="rounded-lg bg-emerald-50 p-3 text-sm text-emerald-700">
          Class updated successfully.
        </p>
      ) : null}

      {classes.length === 0 ? (
        <p className="rounded-lg bg-zinc-50 p-4 text-sm text-zinc-600">
          No classes found.
        </p>
      ) : (
        <div className="overflow-x-auto rounded-xl border border-zinc-200">
          <table className="min-w-full text-sm">
            <thead className="bg-zinc-50 text-left text-xs font-semibold uppercase tracking-wide text-zinc-600">
              <tr>
                <th className="px-4 py-3">Class ID</th>
                <th className="px-4 py-3">Name</th>
                <th className="px-4 py-3">Total Sessions</th>
                <th className="px-4 py-3">Status</th>
                {isSuperAdmin ? <th className="px-4 py-3">Actions</th> : null}
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-100 bg-white">
              {classes.map((cls) => (
                <tr key={cls.class_id} className="hover:bg-zinc-50">
                  <td className="px-4 py-3 font-mono text-xs text-zinc-500">
                    {cls.class_id}
                  </td>
                  <td className="px-4 py-3 font-medium text-zinc-900">
                    <Link
                      href={`/admin/classes/${cls.class_id}/sessions`}
                      className="hover:underline"
                    >
                      {cls.class_name}
                    </Link>
                  </td>
                  <td className="px-4 py-3 text-zinc-700">
                    {cls.total_sessions}
                  </td>
                  <td className="px-4 py-3">
                    <span
                      className={`inline-flex rounded-full px-2 py-0.5 text-xs font-medium ${
                        cls.status === "active"
                          ? "bg-emerald-100 text-emerald-800"
                          : "bg-zinc-100 text-zinc-600"
                      }`}
                    >
                      {cls.status}
                    </span>
                  </td>
                  {isSuperAdmin ? (
                    <td className="px-4 py-3">
                      <EditClassModal
                        classId={cls.class_id}
                        initialName={cls.class_name}
                        initialDescription={cls.description}
                        submitAction={editClassAction}
                      />
                    </td>
                  ) : null}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <Link
        href="/admin/dashboard"
        className="inline-flex rounded-md border border-zinc-300 px-4 py-2 text-sm font-medium text-zinc-800 transition hover:bg-zinc-100"
      >
        Back to Dashboard
      </Link>
    </main>
  );
}

async function loadClassListPageData(): Promise<ClassRow[]> {
  try {
    const client = createConvexHttpClient();
    const result = await client.query(
      makeFunctionReference<"query">("adminClasses:getClassListPageData"),
      {}
    );
    return result;
  } catch {
    return [];
  }
}

import { mutationGeneric, queryGeneric } from "convex/server";
import { v } from "convex/values";

export const getClassListPageData = queryGeneric({
  args: {},
  returns: v.array(
    v.object({
      class_id: v.string(),
      class_name: v.string(),
      description: v.optional(v.string()),
      total_sessions: v.number(),
      status: v.union(v.literal("active"), v.literal("inactive")),
    })
  ),
  handler: async (ctx) => {
    const classes = await ctx.db.query("classes").collect();
    const sessions = await ctx.db.query("sessions").collect();

    const sessionCountByClassId = new Map<string, number>();
    for (const session of sessions) {
      const count = sessionCountByClassId.get(session.class_id) ?? 0;
      sessionCountByClassId.set(session.class_id, count + 1);
    }

    return classes.map((cls) => ({
      class_id: cls.class_id,
      class_name: cls.name,
      description: cls.description,
      total_sessions: sessionCountByClassId.get(cls.class_id) ?? 0,
      status: cls.status,
    }));
  },
});

export const createClass = mutationGeneric({
  args: {
    name: v.string(),
    description: v.optional(v.string()),
    admin_username: v.string(),
  },
  returns: v.object({
    class_id: v.string(),
  }),
  handler: async (ctx, args) => {
    const now = Date.now();
    const classId = crypto.randomUUID();

    const admin = await ctx.db
      .query("admins")
      .withIndex("by_username", (q) => q.eq("username", args.admin_username))
      .first();

    await ctx.db.insert("classes", {
      class_id: classId,
      name: args.name.trim(),
      description: args.description?.trim(),
      status: "active",
      created_at: now,
    });

    await ctx.db.insert("audit_logs", {
      admin_id: admin?._id,
      action: "class_created",
      entity_type: "classes",
      entity_id: classId,
      metadata: {
        name: args.name.trim(),
        description: args.description?.trim(),
      },
      created_at: now,
    });

    return { class_id: classId };
  },
});

export const updateClass = mutationGeneric({
  args: {
    class_id: v.string(),
    name: v.string(),
    description: v.optional(v.string()),
    admin_username: v.string(),
  },
  returns: v.object({
    class_id: v.string(),
  }),
  handler: async (ctx, args) => {
    const classRecord = await ctx.db
      .query("classes")
      .withIndex("by_class_id", (q) => q.eq("class_id", args.class_id))
      .first();

    if (!classRecord) {
      throw new Error("Class not found.");
    }

    const admin = await ctx.db
      .query("admins")
      .withIndex("by_username", (q) => q.eq("username", args.admin_username))
      .first();

    if (!admin || admin.role !== "super_admin") {
      throw new Error("Only super admins can edit classes.");
    }

    const now = Date.now();
    const nextName = args.name.trim();
    const nextDescription = args.description?.trim() ?? "";

    await ctx.db.patch(classRecord._id, {
      name: nextName,
      description: nextDescription,
    });

    await ctx.db.insert("audit_logs", {
      admin_id: admin._id,
      action: "class_updated",
      entity_type: "classes",
      entity_id: classRecord.class_id,
      metadata: {
        previous_name: classRecord.name,
        next_name: nextName,
        previous_description: classRecord.description ?? "",
        next_description: nextDescription,
      },
      created_at: now,
    });

    return { class_id: classRecord.class_id };
  },
});

